import { cacheTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  content: string;
};

// In-memory store (replaces what would be a database in production)
const posts: Post[] = [
  { id: 1, title: 'First Post', content: 'Welcome to the blog!' },
];

export function getAllPosts(): Post[] {
  return posts;
}

export function addPost(title: string, content: string): Post {
  const post: Post = {
    id: posts.length > 0 ? Math.max(...posts.map(p => p.id)) + 1 : 1,
    title,
    content,
  };
  posts.push(post);
  return post;
}

/**
 * Fetches all posts with caching via the "posts" cache tag.
 * After a post is created, invalidating this tag ensures the next
 * request fetches fresh data rather than serving stale content.
 */
export async function fetchPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');
  return getAllPosts();
}

'use server';

import { revalidateTag } from 'next/cache';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || typeof title !== 'string' || title.trim().length === 0) {
    throw new Error('Title is required');
  }
  if (!content || typeof content !== 'string' || content.trim().length === 0) {
    throw new Error('Content is required');
  }

  addPost(title.trim(), content.trim());

  // Invalidates all cached data tagged with "posts".
  // The next request that reads data tagged "posts" will block and
  // fetch fresh data — no stale content will be served.
  revalidateTag('posts');
}

import { fetchPosts } from '@/lib/posts';
import { createPost } from './actions';

export default async function Home() {
  const posts = await fetchPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: '2rem' }}>
        <div style={{ marginBottom: '0.5rem' }}>
          <label htmlFor="title" style={{ display: 'block', marginBottom: '0.25rem' }}>
            Title
          </label>
          <input
            id="title"
            name="title"
            placeholder="Post title"
            required
            style={{ width: '100%', padding: '0.5rem' }}
          />
        </div>

        <div style={{ marginBottom: '0.5rem' }}>
          <label htmlFor="content" style={{ display: 'block', marginBottom: '0.25rem' }}>
            Content
          </label>
          <textarea
            id="content"
            name="content"
            placeholder="Post content"
            required
            rows={4}
            style={{ width: '100%', padding: '0.5rem' }}
          />
        </div>

        <button
          type="submit"
          style={{ padding: '0.5rem 1rem', cursor: 'pointer' }}
        >
          Create Post
        </button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                marginBottom: '1rem',
                border: '1px solid #ccc',
                borderRadius: 6,
                padding: '1rem',
              }}
            >
              <h2 style={{ margin: '0 0 0.5rem' }}>{post.title}</h2>
              <p style={{ margin: 0 }}>{post.content}</p>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

